from flask_cors import CORS
import json

app = Flask(__name__)
CORS(app)

# Restaurant data
MENU_ITEMS = [
    {"id": 1, "name": "Margherita Pizza", "description": "Classic tomato, mozzarella, basil", "price": 14.99, "category": "pizza"},
    {"id": 2, "name": "Carbonara", "description": "Spaghetti with pancetta, eggs, pecorino", "price": 18.99, "category": "pasta"},
    {"id": 3, "name": "Grilled Salmon", "description": "Atlantic salmon with vegetables", "price": 22.99, "category": "main"},
    {"id": 4, "name": "Caesar Salad", "description": "Romaine lettuce, parmesan, croutons", "price": 12.99, "category": "salad"},
    {"id": 5, "name": "Tiramisu", "description": "Classic Italian dessert", "price": 8.99, "category": "dessert"},
    {"id": 6, "name": "Bruschetta", "description": "Grilled bread with tomatoes and basil", "price": 9.99, "category": "appetizer"},
]

RESTAURANT_INFO = {
    "name": "Luigi's Italian Kitchen",
    "description": "Authentic Italian cuisine with a modern twist",
    "address": "123 Main Street, New York, NY 10001",
    "phone": "(555) 123-4567",
    "hours": "Mon-Sun: 11:00 AM - 10:00 PM",
    "email": "info@luigisitalian.com"
}

@app.route('/api/menu', methods=['GET'])
def get_menu():
    return jsonify({"success": True, "data": MENU_ITEMS})

@app.route('/api/menu/<int:item_id>', methods=['GET'])
def get_menu_item(item_id):
    item = next((item for item in MENU_ITEMS if item["id"] == item_id), None)
    if item:
        return jsonify({"success": True, "data": item})
    return jsonify({"success": False, "error": "Item not found"}), 404

@app.route('/api/contact', methods=['POST'])
def contact():
    data = request.get_json()
    if not data or not data.get('name') or not data.get('message'):
        return jsonify({"success": False, "error": "Name and message required"}), 400
    # In production, you would save this to a database
    print(f"Contact form submission: {data['name']}: {data['message']}")
    return jsonify({"success": True, "message": "Message received!"})

@app.route('/api/about', methods=['GET'])
def get_about():
    return jsonify({"success": True, "data": RESTAURANT_INFO})

@app.route('/', methods=['GET'])
def home():
    return jsonify({"message": "Welcome to Luigi's Italian Kitchen API"})

if __name__ == '__main__':
    app.run(debug=True, port=5000)
"
